def as_to_metadata(%{"type" => @property_value, "propertyID" => key, "value" => value})
    when is_boolean(value) do
  %{type: :boolean, key: key, value: to_string(value)}
end
def as_to_metadata(%{"type" => @property_value, "propertyID" => key, "value" => value})
    when is_float(value) do
  %{type: :float, key: key, value: to_string(value)}
end
def as_to_metadata(%{"type" => @property_value, "propertyID" => key, "value" => value})
    when is_integer(value) do
  %{type: :integer, key: key, value: to_string(value)}
end
def as_to_metadata(%{"type" => @property_value, "propertyID" => key, "value" => value} = args)
    when is_binary(value) do
  additional =
    if Map.has_key?(args, "name") do
      %{title: Map.get(args, "name")}
    else
      %{}
    end

  Map.merge(%{type: :string, key: key, value: value}, additional)
end

def build_tags(tags) do
  Enum.map(tags, fn %Tag{} = tag ->
    %{
      "href" => Endpoint.url() <> "/tags/#{tag.slug}",
      "name" => "##{tag.title}",
      "type" => "Hashtag"
    }
  end)
end

def prepare_public_key(public_key_code) do
  case :public_key.pem_decode(public_key_code) do
    [public_key_entry] -> {:ok, :public_key.pem_entry_decode(public_key_entry)}
    _ -> {:error, :pem_decode_error}
  end
end

def validate_json_response(body, headers) do
  cond do
    !content_type_matches?(headers, "application/json") -> {:error, :bad_content_type}
    !is_map(body) -> {:error, :body_not_json}
    true -> {:ok, body}
  end
end

