def clean(opts \\ []) do
  medias = Medias.find_media_to_clean(opts)

  if Keyword.get(opts, :dry_run, false) do
    {:ok, medias}
  else
    Enum.each(medias, fn media_list ->
      Enum.each(media_list, fn media ->
        Medias.delete_media(media, ignore_file_not_found: true)
      end)
    end)

    {:ok, medias}
  end
end

