def find_favicon_in_root(url, headers) do
  uri = URI.parse(url)
  favicon_url = "#{uri.scheme}://#{uri.host}/favicon.ico"

  case Tesla.head(favicon_url, headers: headers, opts: @options) do
    {:ok, %{status: code}} when code in 200..299 -> {:ok, favicon_url}
    {:ok, %{}} -> {:error, "Error while doing a HEAD request on the favicon"}
    {:error, err} -> {:error, err}
  end
end

def maybe_parse(html) do
  Enum.reduce_while(parsers(), %{}, fn parser, acc ->
    Logger.debug("Using #{inspect(parser)} to parse link")

    case parser.parse(html, acc) do
      {:ok, data} -> {:halt, data}
      {:error, _msg} -> {:cont, acc}
    end
  end)
end

