def list_archived_blog_posts(member) do
  case categories_allowed_to_post(member) do
    [] ->
      {:error, :not_allowed_to_post}

    categories ->
      query =
        from(p in Post,
          where: p.category in ^categories and p.status != :published,
          order_by: [desc: p.published_at]
        )

      {:ok, Repo.all(query)}
  end
end

