def unapproved_events() do
  from(p in Event, where: p.approved == false, order_by: [p.inserted_at]) |> Repo.all()
end

def unapproved_events_count() do
  from(p in Event, where: p.approved == false, select: count(p.id)) |> Repo.one()
end

