def get_working_group_by_slug(slug) do
  case Repo.one(Query.get_wg_by_slug(slug)) do
    %WorkingGroup{} = wg -> {:ok, wg}
    _ -> {:error, :not_found}
  end
end

def get_wg_by_id(id) do
  from(wg in wg_query(), where: wg.id == ^id)
end

def get_wg_by_slug(slug) do
  from(wg in wg_query(), where: wg.slug == ^slug)
end

def get_wg_report_by_member_id(id) do
  from(r in WorkingGroupReport, where: r.member_id == ^id)
end

